export interface Artwork {
  id: string;
  image: string;
  title: string;
  curator: string;
  audio: string;
  createdAt: number;
}

import React, { useState } from 'react';
import { motion, useAnimation } from 'framer-motion';
import { ZoomIn, ZoomOut, RotateCcw } from 'lucide-react';

interface ZoomableImageProps {
  src: string;
  alt: string;
}

const ZoomableImage: React.FC<ZoomableImageProps> = ({ src, alt }) => {
  const [scale, setScale] = useState(1);
  const controls = useAnimation();

  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.5, 4));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.5, 1));
  const handleReset = () => {
    setScale(1);
    controls.start({ x: 0, y: 0 });
  };

  return (
    <div className="relative w-full h-[45vh] overflow-hidden bg-neutral-100 rounded-t-3xl border-b border-neutral-200 shadow-inner group">
      <motion.div
        animate={controls}
        className="w-full h-full cursor-move"
        drag={scale > 1}
        dragConstraints={{ left: -200 * scale, right: 200 * scale, top: -200 * scale, bottom: 200 * scale }}
      >
        <motion.img
          src={src}
          alt={alt}
          animate={{ scale }}
          transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          className="w-full h-full object-cover origin-center"
          draggable={false}
        />
      </motion.div>

      {/* Zoom Controls Overlay */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
        <button 
          onClick={handleZoomIn}
          className="p-2 bg-white/80 backdrop-blur-md rounded-full shadow-lg hover:bg-white text-neutral-800"
        >
          <ZoomIn size={20} />
        </button>
        <button 
          onClick={handleZoomOut}
          className="p-2 bg-white/80 backdrop-blur-md rounded-full shadow-lg hover:bg-white text-neutral-800"
        >
          <ZoomOut size={20} />
        </button>
        <button 
          onClick={handleReset}
          className="p-2 bg-white/80 backdrop-blur-md rounded-full shadow-lg hover:bg-white text-neutral-800"
        >
          <RotateCcw size={20} />
        </button>
      </div>

      {scale > 1 && (
        <div className="absolute top-4 left-4 px-3 py-1 bg-black/50 text-white text-xs rounded-full backdrop-blur-sm">
          확대됨 (x{scale.toFixed(1)}) - 드래그하여 이동
        </div>
      )}
    </div>
  );
};

export default ZoomableImage;

import React, { useState, useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Volume2 } from 'lucide-react';

interface AudioPlayerProps {
  src: string;
}

const AudioPlayer: React.FC<AudioPlayerProps> = ({ src }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const setAudioData = () => setDuration(audio.duration);
    const setAudioTime = () => setCurrentTime(audio.currentTime);

    audio.addEventListener('loadeddata', setAudioData);
    audio.addEventListener('timeupdate', setAudioTime);
    audio.addEventListener('ended', () => setIsPlaying(false));

    return () => {
      audio.removeEventListener('loadeddata', setAudioData);
      audio.removeEventListener('timeupdate', setAudioTime);
    };
  }, [src]);

  const togglePlay = () => {
    if (isPlaying) {
      audioRef.current?.pause();
    } else {
      audioRef.current?.play();
    }
    setIsPlaying(!isPlaying);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = Number(e.target.value);
    setCurrentTime(time);
    if (audioRef.current) {
      audioRef.current.currentTime = time;
    }
  };

  const skip = (amount: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime += amount;
    }
  };

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds.toString().padStart(2, '0')}`;
  };

  return (
    <div className="w-full px-6 py-4 bg-white rounded-2xl shadow-sm border border-neutral-100">
      <audio ref={audioRef} src={src} />

      {/* Progress Bar */}
      <div className="mb-4">
        <input
          type="range"
          min="0"
          max={duration || 0}
          value={currentTime}
          onChange={handleSeek}
          className="w-full h-1 bg-neutral-200 rounded-lg appearance-none cursor-pointer accent-neutral-800"
        />
        <div className="flex justify-between text-[10px] text-neutral-400 mt-1 font-medium">
          <span>{formatTime(currentTime)}</span>
          <span>{formatTime(duration)}</span>
        </div>
      </div>

      {/* Controls */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4 flex-1 justify-center">
          <button onClick={() => skip(-10)} className="text-neutral-400 hover:text-neutral-600">
            <SkipBack size={20} />
          </button>

          <button 
            onClick={togglePlay}
            className="w-12 h-12 flex items-center justify-center bg-neutral-900 text-white rounded-full shadow-lg active:scale-95 transition-transform"
          >
            {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} className="ml-1" fill="currentColor" />}
          </button>

          <button onClick={() => skip(10)} className="text-neutral-400 hover:text-neutral-600">
            <SkipForward size={20} />
          </button>
        </div>

        <div className="absolute right-10 text-neutral-300">
          <Volume2 size={18} />
        </div>
      </div>
    </div>
  );
};

export default AudioPlayer;

