import React, { useState } from 'react';
import { X, Upload, Image as ImageIcon, Music, User, Type } from 'lucide-react';
import { Artwork } from '../types';

interface AddWorkModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (artwork: Artwork) => void;
}

const AddWorkModal: React.FC<AddWorkModalProps> = ({ isOpen, onClose, onAdd }) => {
  const [title, setTitle] = useState('');
  const [curator, setCurator] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [audio, setAudio] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAudioChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setAudio(url);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !curator || !image || !audio) {
      alert('모든 필드를 입력해주세요.');
      return;
    }

    onAdd({
      id: Math.random().toString(36).substr(2, 9),
      title,
      curator,
      image,
      audio,
      createdAt: Date.now(),
    });

    // Reset
    setTitle('');
    setCurator('');
    setImage(null);
    setAudio(null);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-lg bg-white rounded-3xl overflow-hidden shadow-2xl">
        <div className="px-6 py-4 flex justify-between items-center border-b border-neutral-100">
          <h3 className="text-lg font-bold text-neutral-800">새 작품 추가</h3>
          <button onClick={onClose} className="p-2 text-neutral-400 hover:text-neutral-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-4">
            {/* Title Input */}
            <div>
              <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                <Type size={14} /> 작품 제목
              </label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="작품의 제목을 입력하세요"
                className="w-full px-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-neutral-200 transition-all"
              />
            </div>

            {/* Curator Input */}
            <div>
              <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                <User size={14} /> 큐레이터 이름
              </label>
              <input
                type="text"
                value={curator}
                onChange={(e) => setCurator(e.target.value)}
                placeholder="큐레이터의 이름을 입력하세요"
                className="w-full px-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-neutral-200 transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              {/* Image Input */}
              <div className="relative">
                <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                  <ImageIcon size={14} /> 이미지
                </label>
                <div className={`relative h-24 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all ${image ? 'border-green-400 bg-green-50' : 'border-neutral-200 hover:border-neutral-300'}`}>
                  {image ? (
                    <img src={image} className="h-full w-full object-cover rounded-xl" />
                  ) : (
                    <>
                      <Upload size={20} className="text-neutral-400 mb-1" />
                      <span className="text-[10px] text-neutral-500">사진 업로드</span>
                    </>
                  )}
                  <input type="file" accept="image/*" onChange={handleImageChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                </div>
              </div>

              {/* Audio Input */}
              <div className="relative">
                <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                  <Music size={14} /> 음성 파일
                </label>
                <div className={`relative h-24 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all ${audio ? 'border-green-400 bg-green-50' : 'border-neutral-200 hover:border-neutral-300'}`}>
                   {audio ? (
                     <div className="flex flex-col items-center">
                        <Music size={24} className="text-green-500 mb-1" />
                        <span className="text-[10px] text-green-600 font-medium">업로드 완료</span>
                     </div>
                   ) : (
                    <>
                      <Upload size={20} className="text-neutral-400 mb-1" />
                      <span className="text-[10px] text-neutral-500">MP3 업로드</span>
                    </>
                   )}
                  <input type="file" accept="audio/*" onChange={handleAudioChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                </div>
              </div>
            </div>
          </div>

          <button
            type="submit"
            className="w-full py-4 bg-neutral-900 text-white rounded-xl font-bold hover:bg-neutral-800 shadow-lg active:scale-[0.98] transition-all"
          >
            갤러리에 추가하기
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddWorkModal;

import React, { useState, useEffect } from 'react';
import { Plus, ChevronLeft, ChevronRight, Info } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import GalleryCard from './components/GalleryCard';
import AddWorkModal from './components/AddWorkModal';
import { Artwork } from './types';

const INITIAL_ARTWORKS: Artwork[] = [
  {
    id: '1',
    title: 'Starry Night',
    curator: 'Vincent van Gogh',
    image: 'https://picsum.photos/seed/starry/1200/1800',
    audio: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3',
    createdAt: Date.now()
  },
  {
    id: '2',
    title: 'The Great Wave',
    curator: 'Katsushika Hokusai',
    image: 'https://picsum.photos/seed/wave/1200/1800',
    audio: 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3',
    createdAt: Date.now()
  }
];

const App: React.FC = () => {
  const [artworks, setArtworks] = useState<Artwork[]>(INITIAL_ARTWORKS);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [direction, setDirection] = useState(0);

  const handleAddArtwork = (newWork: Artwork) => {
    setArtworks([newWork, ...artworks]);
    setCurrentIndex(0);
  };

  const slideVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 500 : -500,
      opacity: 0,
      scale: 0.9,
    }),
    center: {
      zIndex: 1,
      x: 0,
      opacity: 1,
      scale: 1,
    },
    exit: (direction: number) => ({
      zIndex: 0,
      x: direction < 0 ? 500 : -500,
      opacity: 0,
      scale: 0.9,
    })
  };

  const paginate = (newDirection: number) => {
    const nextIndex = currentIndex + newDirection;
    if (nextIndex >= 0 && nextIndex < artworks.length) {
      setDirection(newDirection);
      setCurrentIndex(nextIndex);
    }
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-neutral-100 flex flex-col">
      {/* Header */}
      <header className="fixed top-0 w-full z-40 bg-white/50 backdrop-blur-xl border-b border-neutral-200/50 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-neutral-900 rounded-lg flex items-center justify-center">
            <span className="text-white font-black italic text-xs">A</span>
          </div>
          <h1 className="text-sm font-bold tracking-tight text-neutral-800 uppercase">Art Archive</h1>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center gap-2 px-4 py-2 bg-neutral-900 text-white rounded-full text-xs font-bold hover:bg-neutral-800 transition-all shadow-md active:scale-95"
        >
          <Plus size={16} /> 작품 추가
        </button>
      </header>

      {/* Main Content (Slider Container) */}
      <main className="flex-grow flex items-center justify-center pt-24 pb-12 px-6 relative overflow-hidden">
        {artworks.length > 0 ? (
          <div className="relative w-full max-w-[400px] h-full flex items-center justify-center">
            <AnimatePresence initial={false} custom={direction}>
              <motion.div
                key={artworks[currentIndex].id}
                custom={direction}
                variants={slideVariants}
                initial="enter"
                animate="center"
                exit="exit"
                transition={{
                  x: { type: "spring", stiffness: 300, damping: 30 },
                  opacity: { duration: 0.2 },
                  scale: { duration: 0.3 }
                }}
                className="absolute w-full h-full flex items-center justify-center"
              >
                <GalleryCard artwork={artworks[currentIndex]} />
              </motion.div>
            </AnimatePresence>
          </div>
        ) : (
          <div className="text-center text-neutral-400">
            <Info className="mx-auto mb-2 opacity-20" size={48} />
            <p>작품이 없습니다. 새로운 작품을 추가해보세요.</p>
          </div>
        )}

        {/* Navigation Arrows (visible on desktop) */}
        <div className="hidden md:flex absolute inset-0 pointer-events-none items-center justify-between px-12">
           <button 
              disabled={currentIndex === 0}
              onClick={() => paginate(-1)}
              className={`p-4 rounded-full bg-white shadow-xl pointer-events-auto transition-all ${currentIndex === 0 ? 'opacity-20 cursor-not-allowed' : 'hover:scale-110 active:scale-95'}`}
            >
              <ChevronLeft size={32} />
           </button>
           <button 
              disabled={currentIndex === artworks.length - 1}
              onClick={() => paginate(1)}
              className={`p-4 rounded-full bg-white shadow-xl pointer-events-auto transition-all ${currentIndex === artworks.length - 1 ? 'opacity-20 cursor-not-allowed' : 'hover:scale-110 active:scale-95'}`}
            >
              <ChevronRight size={32} />
           </button>
        </div>
      </main>

      {/* Footer (Indicator) */}
      <footer className="h-20 flex flex-col items-center justify-center">
         <div className="flex gap-2 mb-2">
           {artworks.map((_, i) => (
             <div 
                key={i} 
                className={`h-1.5 rounded-full transition-all duration-300 ${i === currentIndex ? 'w-8 bg-neutral-800' : 'w-1.5 bg-neutral-300'}`}
             />
           ))}
         </div>
         <p className="text-[10px] text-neutral-400 font-medium tracking-widest uppercase">
           Slide to Navigate ({currentIndex + 1} / {artworks.length})
         </p>
      </footer>

      {/* Add Modal */}
      <AddWorkModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onAdd={handleAddArtwork} 
      />
    </div>
  );
};

export default App;

