import React, { useState } from 'react';
import { motion, useAnimation } from 'framer-motion';
import { ZoomIn, ZoomOut, RotateCcw } from 'lucide-react';

interface ZoomableImageProps {
  src: string;
  alt: string;
}

const ZoomableImage: React.FC<ZoomableImageProps> = ({ src, alt }) => {
  const [scale, setScale] = useState(1);
  const controls = useAnimation();

  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.5, 4));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.5, 1));
  const handleReset = () => {
    setScale(1);
    controls.start({ x: 0, y: 0 });
  };

  return (
    <div className="relative w-full h-[60vh] overflow-hidden bg-neutral-900 rounded-t-[2rem] border-b border-neutral-100 shadow-inner group">
      {/* Background Blur to fill empty space without distorting original image */}
      <div 
        className="absolute inset-0 opacity-30 blur-2xl scale-110 pointer-events-none"
        style={{ 
          backgroundImage: `url(${src})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center'
        }}
      />

      <motion.div
        animate={controls}
        className="relative w-full h-full cursor-move flex items-center justify-center"
        drag={scale > 1}
        dragConstraints={{ left: -300 * scale, right: 300 * scale, top: -300 * scale, bottom: 300 * scale }}
      >
        <motion.img
          src={src}
          alt={alt}
          animate={{ scale }}
          transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          className="max-w-full max-h-full object-contain origin-center shadow-2xl"
          draggable={false}
        />
      </motion.div>

      {/* Zoom Controls Overlay */}
      <div className="absolute bottom-6 right-6 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-10">
        <button 
          onClick={handleZoomIn}
          className="p-3 bg-white/90 backdrop-blur-md rounded-full shadow-xl hover:bg-white text-neutral-800 transition-colors"
        >
          <ZoomIn size={22} />
        </button>
        <button 
          onClick={handleZoomOut}
          className="p-3 bg-white/90 backdrop-blur-md rounded-full shadow-xl hover:bg-white text-neutral-800 transition-colors"
        >
          <ZoomOut size={22} />
        </button>
        <button 
          onClick={handleReset}
          className="p-3 bg-white/90 backdrop-blur-md rounded-full shadow-xl hover:bg-white text-neutral-800 transition-colors"
        >
          <RotateCcw size={22} />
        </button>
      </div>

      {scale > 1 && (
        <div className="absolute top-6 left-6 px-4 py-1.5 bg-black/60 text-white text-[10px] font-bold rounded-full backdrop-blur-md uppercase tracking-widest z-10">
          Zoomed x{scale.toFixed(1)}
        </div>
      )}
    </div>
  );
};

export default ZoomableImage;

import React, { useState } from 'react';
import { X, Upload, Image as ImageIcon, Music, User, Type } from 'lucide-react';
import { Artwork } from '../types';

interface AddWorkModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (artwork: Artwork) => void;
}

const AddWorkModal: React.FC<AddWorkModalProps> = ({ isOpen, onClose, onAdd }) => {
  const [title, setTitle] = useState('');
  const [curator, setCurator] = useState('');
  const [image, setImage] = useState<string | null>(null);
  const [audio, setAudio] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAudioChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setAudio(url);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !curator || !image || !audio) {
      alert('모든 필드를 입력해주세요.');
      return;
    }

    onAdd({
      id: Math.random().toString(36).substr(2, 9),
      title,
      curator,
      image,
      audio,
      createdAt: Date.now(),
    });

    // Reset
    setTitle('');
    setCurator('');
    setImage(null);
    setAudio(null);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-lg bg-white rounded-3xl overflow-hidden shadow-2xl">
        <div className="px-6 py-4 flex justify-between items-center border-b border-neutral-100">
          <h3 className="text-lg font-bold text-neutral-800">새 작품 추가</h3>
          <button onClick={onClose} className="p-2 text-neutral-400 hover:text-neutral-600 transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-4">
            {/* Title Input */}
            <div>
              <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                <Type size={14} /> 작품 제목
              </label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="작품의 제목을 입력하세요"
                className="w-full px-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-neutral-200 transition-all"
              />
            </div>

            {/* Curator Input */}
            <div>
              <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                <User size={14} /> 큐레이터 이름
              </label>
              <input
                type="text"
                value={curator}
                onChange={(e) => setCurator(e.target.value)}
                placeholder="큐레이터의 이름을 입력하세요"
                className="w-full px-4 py-3 bg-neutral-50 border border-neutral-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-neutral-200 transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              {/* Image Input */}
              <div className="relative">
                <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                  <ImageIcon size={14} /> 이미지
                </label>
                <div className={`relative h-24 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all overflow-hidden ${image ? 'border-green-400 bg-neutral-900' : 'border-neutral-200 hover:border-neutral-300'}`}>
                  {image ? (
                    <img src={image} className="h-full w-full object-contain rounded-xl" />
                  ) : (
                    <>
                      <Upload size={20} className="text-neutral-400 mb-1" />
                      <span className="text-[10px] text-neutral-500">사진 업로드</span>
                    </>
                  )}
                  <input type="file" accept="image/*" onChange={handleImageChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                </div>
              </div>

              {/* Audio Input */}
              <div className="relative">
                <label className="flex items-center gap-2 text-xs font-semibold text-neutral-500 uppercase tracking-wider mb-1.5">
                  <Music size={14} /> 음성 파일
                </label>
                <div className={`relative h-24 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all ${audio ? 'border-green-400 bg-green-50' : 'border-neutral-200 hover:border-neutral-300'}`}>
                   {audio ? (
                     <div className="flex flex-col items-center">
                        <Music size={24} className="text-green-500 mb-1" />
                        <span className="text-[10px] text-green-600 font-medium">업로드 완료</span>
                     </div>
                   ) : (
                    <>
                      <Upload size={20} className="text-neutral-400 mb-1" />
                      <span className="text-[10px] text-neutral-500">MP3 업로드</span>
                    </>
                   )}
                  <input type="file" accept="audio/*" onChange={handleAudioChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                </div>
              </div>
            </div>
          </div>

          <button
            type="submit"
            className="w-full py-4 bg-neutral-900 text-white rounded-xl font-bold hover:bg-neutral-800 shadow-lg active:scale-[0.98] transition-all"
          >
            갤러리에 추가하기
          </button>
        </form>
      </div>
    </div>
  );
};

