const GalleryView = ({ artworks, currentIndex, setCurrentIndex }: { artworks: Artwork[], currentIndex: number, setCurrentIndex: any }) => {
  const [direction, setDirection] = useState(0);

  const slideVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 600 : -600,
      opacity: 0,
      scale: 0.95,
      rotate: direction > 0 ? 5 : -5,
    }),
    center: {
      zIndex: 1,
      x: 0,
      opacity: 1,
      scale: 1,
      rotate: 0,
    },
    exit: (direction: number) => ({
      zIndex: 0,
      x: direction < 0 ? 600 : -600,
      opacity: 0,
      scale: 0.95,
      rotate: direction < 0 ? 5 : -5,
    })
  };

  const paginate = (newDirection: number) => {
    const nextIndex = currentIndex + newDirection;
    if (nextIndex >= 0 && nextIndex < artworks.length) {
      setDirection(newDirection);
      setCurrentIndex(nextIndex);
    }
  };

  return (
    <>
      <AnimatePresence initial={false} custom={direction}>
        <motion.div
          key={artworks[currentIndex].id}
          custom={direction}
          variants={slideVariants}
          initial="enter"
          animate="center"
          exit="exit"
          transition={{
            x: { type: "spring", stiffness: 260, damping: 26 },
            opacity: { duration: 0.25 },
            rotate: { duration: 0.4 }
          }}
          className="absolute w-full h-full flex items-center justify-center"
          drag="x"
          dragConstraints={{ left: 0, right: 0 }}
          onDragEnd={(_, info) => {
            const swipeThreshold = 50;
            if (info.offset.x < -swipeThreshold) paginate(1);
            else if (info.offset.x > swipeThreshold) paginate(-1);
          }}
        >
          <GalleryCard artwork={artworks[currentIndex]} />
        </motion.div>
      </AnimatePresence>

      <div className="absolute -bottom-6 flex gap-1">
        {artworks.map((_, i) => (
          <div key={i} className={`h-1 rounded-full transition-all duration-300 ${i === currentIndex ? 'w-6 bg-neutral-900' : 'w-1 bg-neutral-200'}`} />
        ))}
      </div>
    </>
  );
};

