type TabType = 'GALLERY' | 'COLLECTION' | 'ABOUT';
const TABS: TabType[] = ['GALLERY', 'COLLECTION', 'ABOUT'];

const App: React.FC = () => {
  const [artworks, setArtworks] = useState<Artwork[]>(INITIAL_ARTWORKS);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('GALLERY');
  const [tabDirection, setTabDirection] = useState(0);

  const handleAddArtwork = (newWork: Artwork) => {
    setArtworks([newWork, ...artworks]);
    if (activeTab === 'GALLERY') setCurrentIndex(0);
  };

  const switchTab = (newTab: TabType) => {
    const oldIndex = TABS.indexOf(activeTab);
    const newIndex = TABS.indexOf(newTab);
    if (oldIndex === newIndex) return;

    setTabDirection(newIndex > oldIndex ? 1 : -1);
    setActiveTab(newTab);
  };

  const jumpToGallery = (index: number) => {
    setCurrentIndex(index);
    // 컬렉션에서 갤러리로 갈 때는 무조건 왼쪽으로 밀리는 느낌을 줌
    setTabDirection(-1); 
    setActiveTab('GALLERY');
  };

  const pageVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? '100%' : '-100%',
      opacity: 0
    }),
    center: {
      x: 0,
      opacity: 1
    },
    exit: (direction: number) => ({
      x: direction < 0 ? '100%' : '-100%',
      opacity: 0
    })
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-neutral-50 flex flex-col font-sans">
      {/* Floating Add Button */}
      <div className="fixed top-6 right-6 z-50">
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center gap-2 px-4 py-2 bg-neutral-900/90 backdrop-blur-md text-white rounded-full text-[10px] font-bold hover:bg-neutral-800 transition-all shadow-xl active:scale-95 border border-white/10"
        >
          <Plus size={12} /> 작품 추가
        </button>
      </div>

      {/* Main Content Area */}
      <div className="flex-grow relative overflow-hidden">
        <AnimatePresence initial={false} custom={tabDirection} mode="wait">
          <motion.div
            key={activeTab}
            custom={tabDirection}
            variants={pageVariants}
            initial="enter"
            animate="center"
            exit="exit"
            transition={{ type: "spring", stiffness: 350, damping: 35 }}
            className="absolute inset-0 w-full h-full"
          >
            {activeTab === 'GALLERY' && (
              <main className="w-full h-full flex flex-col items-center justify-center pt-8 pb-20 px-4">
                {artworks.length > 0 ? (
                  <div className="relative w-full max-w-[420px] h-[80vh] flex items-center justify-center">
                    <GalleryView 
                      artworks={artworks} 
                      currentIndex={currentIndex} 
                      setCurrentIndex={setCurrentIndex} 
                    />
                  </div>
                ) : (
                  <EmptyState />
                )}
              </main>
            )}

            {activeTab === 'COLLECTION' && (
              <main className="w-full h-full pt-20 pb-28 px-6 overflow-y-auto custom-scrollbar">
                <div className="max-w-4xl mx-auto">
                  <header className="mb-10 flex justify-between items-end">
                    <div>
                      <h2 className="text-3xl font-black serif text-neutral-900">Collection</h2>
                      <p className="text-[10px] text-neutral-400 font-bold uppercase tracking-widest mt-2">Explore {artworks.length} masterpieces</p>
                    </div>
                  </header>

                  <div className="grid grid-cols-2 gap-5">
                    {artworks.map((work, index) => (
                      <motion.button
                        key={work.id}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.05 }}
                        onClick={() => jumpToGallery(index)}
                        className={`group relative aspect-[3/4] rounded-[2rem] overflow-hidden transition-all duration-500 text-left ${index === currentIndex ? 'ring-4 ring-neutral-900 ring-offset-4' : 'shadow-sm border border-neutral-200'}`}
                      >
                        <img src={work.image} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" />

                        {/* Status Overlays */}
                        <div className="absolute inset-0 bg-neutral-900/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-5">
                           <div className="flex justify-between items-center text-white">
                             <div className="overflow-hidden">
                               <p className="font-bold text-xs truncate">{work.title}</p>
                               <p className="text-[8px] opacity-70 uppercase tracking-widest truncate">{work.curator}</p>
                             </div>
                             <ArrowUpRight size={14} className="shrink-0 ml-2" />
                           </div>
                        </div>

                        {/* Top Indicator */}
                        <div className="absolute top-4 left-4 right-4 flex justify-between items-start pointer-events-none">
                           <span className="px-2.5 py-1 bg-white/90 backdrop-blur-md text-neutral-900 text-[9px] font-black rounded-full shadow-sm">
                             #0{index + 1}
                           </span>
                           {index === currentIndex && (
                             <div className="bg-neutral-900 text-white p-1 rounded-full shadow-lg">
                               <CheckCircle2 size={12} />
                             </div>
                           )}
                        </div>
                      </motion.button>
                    ))}
                  </div>
                </div>
              </main>
            )}

            {activeTab === 'ABOUT' && (
              <main className="w-full h-full pt-20 pb-24 px-8 overflow-y-auto flex items-center justify-center text-center">
                <div className="max-w-md space-y-6">
                  <div className="w-20 h-20 bg-neutral-900 rounded-[2.5rem] mx-auto flex items-center justify-center shadow-2xl mb-8">
                    <SquareLibrary className="text-white" size={32} />
                  </div>
                  <h2 className="text-2xl font-bold serif">Curator's Note</h2>
                  <p className="text-sm text-neutral-500 leading-relaxed italic">
                    "예술은 눈에 보이는 것을 재현하는 것이 아니라, 보이지 않는 것을 보이게 만드는 것이다."
                  </p>
                  <p className="text-xs text-neutral-400 leading-relaxed">
                    이 디지털 아카이브는 일상의 순간을 예술로 승화시키고자 하는 모든 창작자들을 위해 설계되었습니다. 고해상도 줌 기능과 개인화된 오디오 가이드를 통해 작품의 깊이를 느껴보세요.
                  </p>
                  <div className="pt-8 flex justify-center gap-10">
                    <div className="text-center">
                      <p className="text-2xl font-black">{artworks.length}</p>
                      <p className="text-[9px] text-neutral-400 font-bold uppercase tracking-widest mt-1">Total Works</p>
                    </div>
                    <div className="w-px h-10 bg-neutral-200 self-center" />
                    <div className="text-center">
                      <p className="text-2xl font-black">1</p>
                      <p className="text-[9px] text-neutral-400 font-bold uppercase tracking-widest mt-1">Exhibition</p>
                    </div>
                  </div>
                </div>
              </main>
            )}
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Swipable Bottom Navigation Bar */}
      <footer className="fixed bottom-0 w-full h-24 flex items-center justify-center px-6 z-50">
        <div className="relative w-full max-w-[360px] h-14 bg-white/70 backdrop-blur-3xl rounded-full border border-white/50 shadow-[0_12px_40px_rgba(0,0,0,0.12)] flex items-center p-1 overflow-hidden">

          <motion.div 
            className="absolute h-10 bg-neutral-900 rounded-full z-0"
            animate={{ 
              width: `${100 / TABS.length}%`,
              x: `${TABS.indexOf(activeTab) * 100}%` 
            }}
            transition={{ type: "spring", stiffness: 450, damping: 35 }}
          />

          {TABS.map((tab) => (
            <button
              key={tab}
              onClick={() => switchTab(tab)}
              className={`relative flex-1 h-full flex items-center justify-center z-10 text-[9px] font-black tracking-[0.15em] transition-colors duration-300 ${activeTab === tab ? 'text-white' : 'text-neutral-400'}`}
            >
              {tab}
            </button>
          ))}

          <motion.div 
            className="absolute inset-0 z-20 cursor-grab active:cursor-grabbing"
            drag="x"
            dragConstraints={{ left: 0, right: 0 }}
            onDragEnd={(_, info) => {
              const threshold = 50;
              const currentIndex = TABS.indexOf(activeTab);
              if (info.offset.x < -threshold && currentIndex < TABS.length - 1) {
                switchTab(TABS[currentIndex + 1]);
              } else if (info.offset.x > threshold && currentIndex > 0) {
                switchTab(TABS[currentIndex - 1]);
              }
            }}
          />
        </div>
      </footer>

      <AddWorkModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onAdd={handleAddArtwork} 
      />
    </div>
  );
};

// Sub-component: Gallery Logic
const GalleryView = ({ artworks, currentIndex, setCurrentIndex }: { artworks: Artwork[], currentIndex: number, setCurrentIndex: any }) => {
  const [direction, setDirection] = useState(0);

  const slideVariants = {
    enter: (direction: number) => ({
      x: direction > 0 ? 600 : -600,
      opacity: 0,
      scale: 0.95,
      rotate: direction > 0 ? 5 : -5,
    }),
    center: {
      zIndex: 1,
      x: 0,
      opacity: 1,
      scale: 1,
      rotate: 0,
    },
    exit: (direction: number) => ({
      zIndex: 0,
      x: direction < 0 ? 600 : -600,
      opacity: 0,
      scale: 0.95,
      rotate: direction < 0 ? 5 : -5,
    })
  };

  const paginate = (newDirection: number) => {
    const nextIndex = currentIndex + newDirection;
    if (nextIndex >= 0 && nextIndex < artworks.length) {
      setDirection(newDirection);
      setCurrentIndex(nextIndex);
    }
  };

  return (
    <>
      <AnimatePresence initial={false} custom={direction}>
        <motion.div
          key={artworks[currentIndex].id}
          custom={direction}
          variants={slideVariants}
          initial="enter"
          animate="center"
          exit="exit"
          transition={{
            x: { type: "spring", stiffness: 260, damping: 26 },
            opacity: { duration: 0.25 },
            rotate: { duration: 0.4 }
          }}
          className="absolute w-full h-full flex items-center justify-center"
          drag="x"
          dragConstraints={{ left: 0, right: 0 }}
          onDragEnd={(_, info) => {
            const swipeThreshold = 50;
            if (info.offset.x < -swipeThreshold) paginate(1);
            else if (info.offset.x > swipeThreshold) paginate(-1);
          }}
        >
          <GalleryCard artwork={artworks[currentIndex]} />
        </motion.div>
      </AnimatePresence>

      <div className="absolute -bottom-10 flex gap-2">
        {artworks.map((_, i) => (
          <button
            key={i}
            onClick={() => {
              setDirection(i > currentIndex ? 1 : -1);
              setCurrentIndex(i);
            }}
            className={`h-1.5 rounded-full transition-all duration-300 ${i === currentIndex ? 'w-8 bg-neutral-900' : 'w-1.5 bg-neutral-200'}`}
          />
        ))}
      </div>
    </>
  );
};

const EmptyState = () => (
  <div className="text-center text-neutral-400">
    <Info className="mx-auto mb-2 opacity-20" size={48} />
    <p className="text-sm font-medium">전시된 작품이 없습니다.</p>
  </div>
);

export default App;

